import React, { useState } from "react";
import {
  View,
  Text,
  StyleSheet,
  ScrollView,
  Pressable,
  Platform,
  Image,
} from "react-native";
import { router, useLocalSearchParams } from "expo-router";
import { Ionicons } from "@expo/vector-icons";
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  withSequence,
} from "react-native-reanimated";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import * as Haptics from "expo-haptics";
import getColors from "@/constants/colors";
import { useTheme } from "@/context/ThemeContext";
import { formatPrice } from "@/constants/data";
import { useCart } from "@/context/CartContext";
import { useProducts } from "@/context/ProductsContext";
import { useTranslation } from "@/lib/I18nProvider";
import { resolveImageUrl } from "@/lib/query-client";

const BADGE_CONFIG: Record<string, { label: string; color: string }> = {
  sale: { label: "Chegirma", color: "#EF4444" },
  new: { label: "Yangi", color: "#3B82F6" },
  hot: { label: "Ommabop", color: "#F97316" },
};

const CATEGORY_PAIRS: Record<string, string[]> = {
  ichimliklar: ["shokoladlar", "konservalar"],
  shokoladlar: ["ichimliklar", "konservalar"],
  konservalar: ["ichimliklar", "shokoladlar"],
  fruits: ["dairy", "shokoladlar"],
  vegetables: ["meat", "konservalar"],
  meat: ["vegetables", "dairy"],
  dairy: ["fruits", "konservalar"],
};

export default function ProductDetailScreen() {
  const { id } = useLocalSearchParams<{ id: string }>();
  const insets = useSafeAreaInsets();
  const { products } = useProducts();
  const product = products.find((p) => p.id === id);
  const { addToCart, items, updateQuantity, removeFromCart } = useCart();
  const { t } = useTranslation();
  const { isDarkMode } = useTheme();
  const Colors = getColors(isDarkMode);
  const styles = getStyles(isDarkMode);
  const [liked, setLiked] = useState(false);
  const [addedIds, setAddedIds] = useState<Record<string, boolean>>({});
  const likeScale = useSharedValue(1);
  const cartItemCount = items.find((i) => i.product.id === id)?.quantity ?? 0;
  const btnScale = useSharedValue(1);
  const topPad = Platform.OS === "web" ? 67 : insets.top;

  const likeAnim = useAnimatedStyle(() => ({ transform: [{ scale: likeScale.value }] }));
  const btnAnim = useAnimatedStyle(() => ({ transform: [{ scale: btnScale.value }] }));

  if (!product) {
    return (
      <View style={[styles.container, { justifyContent: "center", alignItems: "center" }]}>
        <Ionicons name="alert-circle-outline" size={48} color={Colors.textMuted} />
        <Text style={styles.notFound}>Mahsulot topilmadi</Text>
        <Pressable style={styles.backBtn} onPress={() => router.back()}>
          <Text style={styles.backBtnText}>Orqaga</Text>
        </Pressable>
      </View>
    );
  }

  const badgeCfg = product.badge ? BADGE_CONFIG[product.badge] : null;

  const relatedProducts = products
    .filter((p) => p.category === product.category && p.id !== product.id)
    .slice(0, 4);

  const pairedCategories = CATEGORY_PAIRS[product.category] ?? [];
  const recommendedProducts = products
    .filter((p) => pairedCategories.includes(p.category) && p.inStock)
    .sort(() => Math.random() - 0.5)
    .slice(0, 8);

  const handleAddToCart = () => {
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    }
    btnScale.value = withSequence(withSpring(0.94), withSpring(1));
    addToCart(product);
  };

  const handleQuickAdd = (p: typeof product) => {
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    addToCart(p);
    setAddedIds((prev) => ({ ...prev, [p.id]: true }));
    setTimeout(() => {
      setAddedIds((prev) => ({ ...prev, [p.id]: false }));
    }, 1500);
  };

  const handleLike = () => {
    setLiked(!liked);
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    likeScale.value = withSequence(withSpring(1.3), withSpring(1));
  };

  return (
    <View style={styles.container}>
      <ScrollView
        showsVerticalScrollIndicator={false}
        contentContainerStyle={{ paddingBottom: 120 }}
      >
        <View style={[styles.hero, { paddingTop: topPad + 60 }]}>
          <Image
            source={{ uri: resolveImageUrl(product.image || "") }}
            style={styles.heroImage}
            resizeMode="cover"
          />
          {badgeCfg && (
            <View style={[styles.heroBadge, { backgroundColor: badgeCfg.color }]}>
              <Text style={styles.heroBadgeText}>{badgeCfg.label}</Text>
            </View>
          )}
        </View>

        <View style={styles.infoCard}>
          <View style={styles.infoHeader}>
            <View style={styles.namePriceBlock}>
              <Text style={styles.productName}>{product.name}</Text>
              {product.brand && <Text style={styles.productBrand}>{product.brand}</Text>}
              <View style={styles.ratingRow}>
                <Ionicons name="star" size={14} color="#F59E0B" />
                <Text style={styles.ratingText}>{product.rating}</Text>
                <Text style={styles.ratingCount}>(128 ta sharh)</Text>
              </View>
            </View>
            <Animated.View style={likeAnim}>
              <Pressable onPress={handleLike} style={styles.likeBtn}>
                <Ionicons
                  name={liked ? "heart" : "heart-outline"}
                  size={22}
                  color={liked ? "#EF4444" : Colors.textMuted}
                />
              </Pressable>
            </Animated.View>
          </View>

          <View style={styles.priceRow}>
            <Text style={styles.price}>{formatPrice(product.price)}</Text>
            <Text style={styles.unit}>/ {product.unit}</Text>
            {product.originalPrice && (
              <Text style={styles.originalPrice}>{formatPrice(product.originalPrice)}</Text>
            )}
            {product.originalPrice && (
              <View style={styles.savingBadge}>
                <Text style={styles.savingText}>
                  -{Math.round((1 - product.price / product.originalPrice) * 100)}%
                </Text>
              </View>
            )}
          </View>

          {product.weight && (
            <View style={styles.metaRow}>
              <Ionicons name="scale-outline" size={14} color={Colors.textMuted} />
              <Text style={styles.metaText}>Og&apos;irlik: {product.weight}</Text>
              <View style={styles.metaDivider} />
              <Ionicons
                name={product.inStock ? "checkmark-circle" : "close-circle"}
                size={14}
                color={product.inStock ? Colors.primary : Colors.error}
              />
              <Text style={[styles.metaText, { color: product.inStock ? Colors.primary : Colors.error }]}>
                {product.inStock ? "Mavjud" : "Mavjud emas"}
              </Text>
            </View>
          )}

          <View style={styles.divider} />

          <Text style={styles.descTitle}>Tavsif</Text>
          <Text style={styles.description}>{product.description}</Text>

          {recommendedProducts.length > 0 && (
            <>
              <View style={styles.divider} />
              <View style={styles.recommendHeader}>
                <Ionicons name="bag-add-outline" size={18} color={Colors.primary} />
                <Text style={styles.recommendTitle}>Haridingizda qo'shib olishingiz mumkin</Text>
              </View>
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                style={styles.recommendScroll}
                contentContainerStyle={{ paddingVertical: 4 }}
              >
                {recommendedProducts.map((rp) => {
                  const alreadyAdded = addedIds[rp.id];
                  const inCart = items.find((i) => i.product.id === rp.id);
                  return (
                    <Pressable
                      key={rp.id}
                      style={styles.recommendCard}
                      onPress={() =>
                        router.push({ pathname: "/product/[id]", params: { id: rp.id } })
                      }
                    >
                      <Image
                        source={{ uri: resolveImageUrl(rp.image || "") }}
                        style={styles.recommendImage}
                        resizeMode="cover"
                      />
                      <Text style={styles.recommendName} numberOfLines={2}>
                        {rp.name}
                      </Text>
                      <Text style={styles.recommendPrice}>{formatPrice(rp.price)}</Text>
                      <Pressable
                        style={[
                          styles.recommendAddBtn,
                          (alreadyAdded || inCart) && styles.recommendAddBtnDone,
                        ]}
                        onPress={(e) => {
                          e.stopPropagation();
                          handleQuickAdd(rp);
                        }}
                      >
                        <Ionicons
                          name={alreadyAdded || inCart ? "checkmark" : "add"}
                          size={16}
                          color="#fff"
                        />
                      </Pressable>
                    </Pressable>
                  );
                })}
              </ScrollView>
            </>
          )}

          {relatedProducts.length > 0 && (
            <>
              <View style={styles.divider} />
              <Text style={styles.descTitle}>Sizga ham yoqishi mumkin</Text>
              <ScrollView horizontal showsHorizontalScrollIndicator={false} style={styles.relatedScroll}>
                {relatedProducts.map((rp) => (
                  <Pressable
                    key={rp.id}
                    style={styles.relatedCard}
                    onPress={() => router.push({ pathname: "/product/[id]", params: { id: rp.id } })}
                  >
                    <View style={styles.relatedImageContainer}>
                      <Image
                        source={{ uri: rp.image }}
                        style={styles.relatedImage}
                        resizeMode="cover"
                      />
                    </View>
                    <Text style={styles.relatedName} numberOfLines={1}>{rp.name}</Text>
                    <Text style={styles.relatedPrice}>{formatPrice(rp.price)}</Text>
                  </Pressable>
                ))}
              </ScrollView>
            </>
          )}
        </View>
      </ScrollView>

      <View style={[styles.header, { top: topPad + 8 }]}>
        <Pressable style={styles.iconBtn} onPress={() => router.back()}>
          <Ionicons name="chevron-back" size={22} color={Colors.text} />
        </Pressable>
      </View>

      <View style={[styles.footer, { paddingBottom: Platform.OS === "web" ? 34 : insets.bottom + 8 }]}>
        {cartItemCount === 0 ? (
          <Animated.View style={[{ flex: 1 }, btnAnim]}>
            <Pressable
              style={[styles.addToCartBtn, !product.inStock && styles.addToCartDisabled]}
              onPress={handleAddToCart}
              disabled={!product.inStock}
            >
              <Ionicons name="cart-outline" size={20} color="#fff" />
              <Text style={styles.addToCartText}>
                {product.inStock ? "Savatga qo'shish" : "Mavjud emas"}
              </Text>
            </Pressable>
          </Animated.View>
        ) : (
          <View style={{ gap: 10 }}>
            <View style={styles.cartControls}>
              <Text style={styles.totalText}>
                {formatPrice(product.price * cartItemCount)}
              </Text>
              <View style={styles.qtyRow}>
                <Pressable
                  style={styles.qtyBtn}
                  onPress={() => {
                    if (cartItemCount === 1) removeFromCart(product.id);
                    else updateQuantity(product.id, cartItemCount - 1);
                  }}
                >
                  <Ionicons name="remove" size={18} color="#fff" />
                </Pressable>
                <Text style={styles.qtyText}>{cartItemCount}</Text>
                <Pressable
                  style={styles.qtyBtn}
                  onPress={() => updateQuantity(product.id, cartItemCount + 1)}
                >
                  <Ionicons name="add" size={18} color="#fff" />
                </Pressable>
              </View>
            </View>
            <Pressable
              style={styles.goToCartBtn}
              onPress={() => router.push("/(tabs)/cart")}
            >
              <Ionicons name="cart" size={18} color="#16A34A" />
              <Text style={styles.goToCartText}>Savatga o'tish</Text>
              <Ionicons name="arrow-forward" size={16} color="#16A34A" />
            </Pressable>
          </View>
        )}
      </View>
    </View>
  );
}

